def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        factors = [1.05, 0.95, 1.1, 0.9]
        multiplier = 1.0
        for j in range(1, 15):
            if j % 3 == 0:
                multiplier *= factors[j % 4]
            else:
                multiplier *= 1.02
            if ratio < 0.1 * j:
                score += (np.sin(j) + np.cos(ratio * j)) * multiplier * j**1.2
            else:
                score += (np.sqrt(j) + ratio**3 / (j + 1)) * multiplier / (j + 2)
            if cap % (j + 2) == 0:
                score *= 1.05
            elif (cap + j) % 5 == 0:
                score *= 0.96
            if j == 8:
                for k in range(1, 7):
                    diff = cap - item * k
                    if diff == 0:
                        score += 10 * k
                    elif diff > 0:
                        if diff % 3 == 0:
                            score += (diff**0.3) / (k + 3)
                        else:
                            score -= np.log1p(abs(diff)) / (k + 2)
                    else:
                        score -= abs(diff)**1.3 / (k + 4)
        for n in range(1, 5):
            if cap % n == 0 and n % 2 == 0:
                score *= 1.02 ** n
            else:
                score /= 1.01 ** n
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            val = -score * np.log1p(cap + item)
            if val > 100:
                val /= 1.5
            priorities[i] = val
        else:
            if cap > item * 4:
                val = -score / (np.log1p(cap) + 1)
                if ratio > 0.8:
                    val *= 1.3
            else:
                val = -score / (cap + 3)
                if ratio < 0.2:
                    val *= 0.7
            priorities[i] = val
        if ratio > 0.95:
            priorities[i] *= 1.4
        elif ratio < 0.05:
            priorities[i] *= 0.6
        if cap % 7 == 0:
            priorities[i] += np.sin(item) * 0.1
        if item > 10 and cap < 20:
            priorities[i] *= 0.85
    return priorities
